import jibo = require('jibo');
const AUDIO_PATH = './resources/music/';

const ASSETS: AudioAssetDescriptor[] = [
   { id: 'audio00', src: AUDIO_PATH + 'mus_yoga_01.ogg', loop:true},
   { id: 'audio01', src: AUDIO_PATH + 'mus_yoga_02.ogg', loop:true},
   { id: 'audio02', src: AUDIO_PATH + 'mus_yoga_03.ogg', loop:true}
];

interface AudioAssetDescriptor {
    id:string;
    src:string;
    loop:boolean
}

class AudioPlayer {
    private _audio: jibo.sound.SoundInstance;
    private _currentAsset:AudioAssetDescriptor;
    private _loadPromise:Promise<void>;
    private _log: typeof jibo.log;

    constructor(log: typeof jibo.log) {
        this._log = log;
    }

    private _preloadAudio():Promise<void> {
        this._loadPromise = new Promise((resolve) => {
            jibo.loader.load(this._currentAsset as any, {
                complete: function(err, results){
                    resolve();
                }
             });
        });
        return this._loadPromise;
    }

    public init():Promise<void> {
        this._currentAsset = ASSETS[Math.floor(Math.random() * ASSETS.length)];
        return this._preloadAudio();
    }

    public pause() {
        this._audio.paused = true;
    }

    public play = () => {
        if(this._audio != null && this._audio.paused === true) {
            this._audio.paused = false;
            return;
        }
        if(!this._loadPromise){
            this._log.error('Audio Player not initialized');
            return;
        }
        //This enables us to lazy-load the music
        //if it's already loaded it will start playing right away
        //if not, it will play as soon as it's done loading.
        this._loadPromise.then(()=>{
            this._audio = jibo.sound.play(this._currentAsset.id);
        });
    };


    public stopAndDestroy() {
        if(this._audio){
            this._audio.destroy();
            this._audio = null;
        }
        this._currentAsset = null;
        this._log = null;
        this._loadPromise = null;
    }
}

export default AudioPlayer;
