interface Part {
    type:string,
    value:string,
    name:string,
    duration?:number
}

class RoundPlayer {
    public name: string;
    private _parts: Part[] = [];
    private _currentPart: number = -1;

    constructor(name:string) {
        this.name = name;
    }

    public get currentPart():Part{
        return this._parts[this._currentPart];
    }

    public addPart(part:Part) {
        this._parts.push(part);
    }

    public addParts(parts:Part[]) {
        this._parts = parts;
    }

    public getNextPart():Part {
        let nextPart = this._parts[++this._currentPart];
        if(!nextPart){
            //reset this RoundPlayer in case it gets used again
            this._currentPart = -1;
        }
        return nextPart;
    }

    public destroy(){
        this._parts = null;
        this._currentPart = null;
    }
}

export {Part};

export default RoundPlayer;
