import Exercise from '../Exercise';
export default class Analytics {
    static skill:Exercise;
    static init(skill:Exercise){
        this.skill = skill;
    }
    static routineStarted(routine:string){
        this.skill.track('Workout Routine Started', {routine});
    }

    static routineEnded(routine:string){
        this.skill.track('Workout Routine Ended', {routine});
    }
}
