import RoundPlayer, {Part} from './Rounds';

export interface RoutineData {
    name: string;
    sequence: string[];
}

class RoutinePlayer {
    private _rounds:RoundPlayer[] = [];
    private _currentRound:number;
    private _sequence:string[] = [];

    public init(routine:RoutineData, rounds:Part[]) {
        this._sequence = routine.sequence;
        this._currentRound = 0;
        this._sequence.forEach((roundName) => {
            let roundPlayer = new RoundPlayer(roundName);
            let parts = rounds.filter(part => part.name === roundName);

            roundPlayer.addParts(parts);
            this._rounds.push(roundPlayer);
        });
    }

    public getNextPart():Part{
        let part = this.getCurrentRound().getNextPart();
        if(!part){
            let newRound = this.getNextRound();
            if(!newRound){
                return;
            }
            else{
                return newRound.getNextPart();
            }
        }
        else{
            return part;
        }
    }

    public getCurrentRound(roundIdx:number = this._currentRound):RoundPlayer {
        return this._rounds.find((roundPlayer) => {
            return roundPlayer.name === this._sequence[roundIdx];;
        });
    }

    public getNextRound():RoundPlayer {
        if (++this._currentRound === this._sequence.length) {
            return null;
        }
        return this.getCurrentRound();
    }

    public destroy() {
        for(let round of this._rounds){
            round.destroy();
        }
        this._rounds = null;
        this._sequence = null;
        this._currentRound = null;
    }
}

export default RoutinePlayer;
