/// <reference path="../../typings/index.d.ts" />
import jibo = require('jibo');
const log = jibo.log.createChild('CustomView');

/**
 * View designed to display eye and clip.
 * @class CustomView
 * @extends module:jibo.rendering.gui.views.EyeView
 */
class CustomView extends jibo.rendering.gui.views.EyeView
{
    /**
     * The default class identifier.
     * Generally used to register the class.
     * @name CustomView.DEFAULT_TYPE
     * @type {String}
     * @private
     * @readOnly
     */
    public static get DEFAULT_TYPE():string {return 'CustomView';}

    private _clip:jibo.rendering.gui.components.Clip;
    private _eyeContainer: jibo.rendering.eye.EyeContainer;
    private _currentAsset:jibo.rendering.gui.AssetDescriptor;
    private _nextAsset:jibo.rendering.gui.AssetDescriptor;
    private _clipSprite:PIXI.Sprite;
    private _hasEyeAnimListener:boolean = false;

    /**
     * The Class name as a string.
     * @name CustomView#_type
     * @type {String}
     * @protected
     * @intdocs
     */
    protected _type:string = CustomView.DEFAULT_TYPE;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Construct View
     */
    constructor () {
        super();
        this.id = 'poseView';
        this._category = jibo.face.views.CATEGORY.DISPLAY;
        this.borderNeeded = false;
        // bind handlers
        this.hideEye = this.hideEye.bind(this);
        this.unhideEye = this.unhideEye.bind(this);
        // TODO :: for now don't support swipe down, but we should
        this.closeOnSwipeDown = false;
    }

    /**
     * FOR OVERRIDE ONLY. DO NOT CALL.
     *
     * Apply data to define and create required Components.
     * The CustomView does not require a component configurations as it manually
     * creates its Components based on data provided within the view configuration.
     * See the class description for an example of the view configuration schema.
     * @method CustomView#applyData
     * @intdocs
     */
    public applyData():void {
        // add clip to store pose images
        this._clip = new jibo.rendering.gui.components.Clip();
        super.addComponent(this._clip);
        super.applyData();
    }

    /**
     * Start the skill
     * @method open
     */
    public open(callback?:Function, transitionType?:string):void {

        try{
          //TODO refine the getting of child
          this._eyeContainer = jibo.face.eye;
          // hide background layer
          this._eyeContainer.background.visible = false;
        }
        catch (err){
          log.warn('Failed to hide background', err);
        }

        // add empty sprite to house pose images
        this._clipSprite = new PIXI.Sprite();
        this._clip.display.addChild(this._clipSprite);
        this._clip.setTargetPosition(jibo.face.width/2, jibo.face.height/2, true);

        super.open(callback, transitionType);
    }

    /**
     * The method for changing the image of the clip.
     * If there is current pose it is faded out, the next image is then faded in.
     * @name CustomView#changeImage
     * @public
     * @param {String} [poseName] The name of the image file to load; the file has to be stored in resources/images/poses/
     */
    public async changeImage(poseName:string) {
        let previousAssetId = (this._currentAsset ? this._currentAsset.id : null);
        if (poseName === previousAssetId) {
            return;
        }
        this._nextAsset = {
            id: poseName,
            type: 'texture',
            src: 'resources/images/poses/'+poseName+'.png'
        };

        return new Promise((resolve) => {
            if (previousAssetId){
                this.hideImage(true, true)
                .then(()=>{
                    this.setImage()
                    .then(() => {
                        this.showImage(true)
                        .then(() => {
                            resolve();
                        })
                    })

                });
            }
            else if (this._eyeContainer.alpha > 0) {
                this.hideEye(true)
                .then(()=>{
                    this.setImage()
                    .then(() => {
                        this.showImage(true)
                        .then(() => {
                            resolve();
                        })
                    })
                });
            }
            else {
                this.setImage()
                .then(() => {
                    this.showImage(true)
                    .then(() => {
                        resolve();
                    })
                })
            }
        })

    }

    public async showImage(fade:boolean = true) {
        // if pose image is shown manage EyeContainer visibility on animation events
        this.addEyeListeners();
        if(fade) {
            return this.fadeInComponent(this._clip.display);
        }
        else {
            this._clip.display.alpha = 1;
        }
    }

    /**
     * The method for hiding the image of the clip.
     * @name CustomView#hideImage
     * @public
     */
    public async hideImage(fade:boolean=true, destroy:boolean=true) {
        // if pose image is being hidden allow eyeconatiner to manage it's own visibility
        this.removeEyeListeners();
        if(fade){
            return this.fadeOutComponent(this._clip.display)
            .then(()=>{
                if (this._currentAsset && destroy){
                    this._clip.emptyDisplay();
                    this.removeAssets(this._currentAsset);
                    this._currentAsset = null;
                }
            });
        }
        else {
            // don't fade, just set alpha to 0
            this._clip.display.alpha = 0;
            if (this._currentAsset && destroy){
                this._clip.emptyDisplay();
                this.removeAssets(this._currentAsset);
                this._currentAsset = null;
            }
        }
    }

    /**
     * The method for hiding the eye, turns off visibility immediately
     * @name CustomView#hideEye
     * @public
     */
    public async hideEye(fade:boolean = true):Promise<void> {
        return new Promise<void>((resolve)=>{
            if(fade && this._eyeContainer.alpha > 0) {
                return this.fadeOutComponent(this._eyeContainer)
                .then(() => {
                    resolve();
                })

            }
            this._eyeContainer.alpha = 0;
            resolve();
        });
    }

    /**
     * The method for unhiding the eye, turns on visibility immediately
     * @name CustomView#hideEye
     * @public
     */
    public async unhideEye(fade:boolean = true):Promise<void> {
        return new Promise<void>((resolve)=>{
            if(fade && this._eyeContainer.alpha < 1) {
                return this.fadeInComponent(this._eyeContainer);
            }
            this._eyeContainer.alpha = 1;
            resolve();
        });
    }

    public addEyeListeners() {
        if(this._eyeContainer && !this._hasEyeAnimListener) {
            this._hasEyeAnimListener = true;
            console.log('addEyeListeners : hasEyeAnimListener TRUE');
            this._eyeContainer.on('removeAnimation', this.hideEye);
            this._eyeContainer.on('addAnimation', this.unhideEye);
        }
    }

    public removeEyeListeners() {
        if(this._eyeContainer && this._hasEyeAnimListener) {
            this._hasEyeAnimListener = false;
            console.log('addEyeListeners : hasEyeAnimListener FALSE');
            this._eyeContainer.removeAllListeners();
        }
    }

    private async setImage():Promise<void> {
        try{
            this.addAssets(this._nextAsset, () => {
                this._currentAsset = this._nextAsset;
                // empty
                this._clip.emptyDisplay();
                // add new image
                let texture:PIXI.Texture = this.assets[this._currentAsset.id];
                this._clipSprite = new PIXI.Sprite(texture);
                this._clipSprite.anchor.x = this._clipSprite.anchor.y = .5;
                this._clip.display.addChild(this._clipSprite);
            });
        }
        catch(e) {
            log.error('error loading pose image: ',e);
        }
    }

    private async fadeOutComponent(display:PIXI.DisplayObject, scaleEase:string = 'backIn', fadeEase:string = 'sineInOut', tweenTime:number = 1000):Promise<void> {
        return new Promise<void>((resolve) => {
            // tween scale
            jibo.rendering.tween.TweenManager.stop(display);
            jibo.rendering.tween.TweenManager.play(display,
                {
                    to: {
                        'scale.x': 1,
                        'scale.y': 1
                    },
                    duration: tweenTime,
                    ease: scaleEase
                },
                () => {
                    //reset pivot and position of stage before callback, halt the alpha tween
                    jibo.rendering.tween.TweenManager.stop(display);
                    display.alpha = 0;
                    resolve();
                }
            );
            // tween alpha
            jibo.rendering.tween.TweenManager.play(display,
                {
                    to: {alpha: 0},
                    duration: tweenTime,
                    ease: fadeEase
                }
            );
        });
    }

    private async fadeInComponent(display:PIXI.DisplayObject, toAlpha:number = 1, scaleEase:string = 'backOut', fadeEase:string = 'sineInOut', tweenTime:number = 1000):Promise<void> {
        return new Promise<void>((resolve) => {
            // tween scale
            jibo.rendering.tween.TweenManager.stop(display);
            jibo.rendering.tween.TweenManager.play(display,
                {
                    to: {
                        'scale.x': 1,
                        'scale.y': 1
                    },
                    from: {
                        'scale.x': 1,
                        'scale.y': 1
                    },
                    duration: tweenTime,
                    ease: scaleEase
                },
                () => {
                    //reset pivot and position of stage before callback, halt the alpha tween
                    jibo.rendering.tween.TweenManager.stop(display);
                    display.alpha = toAlpha;
                    resolve();
                }
            );
            // tween alpha
            jibo.rendering.tween.TweenManager.play(display,
                {
                    to: {alpha: toAlpha},
                    duration: tweenTime,
                    ease: fadeEase
                }
            );
        });
    }

    public cleanUp():void {
        // clean up EyeContainer
        if(this._eyeContainer) {
            // remove listeners
            this.removeEyeListeners();
            // undo changes to background
            this._eyeContainer.background.visible = true;
            // show eye
            this._eyeContainer.alpha = 1;
            // stop tweens
            jibo.rendering.tween.TweenManager.stop(this._eyeContainer);
        }
        // clean up Clip
        if(this._clip) {
            this._clip.stopChildTweens(true);
        }
    }

    /**
     * FOR OVERRIDE ONLY. DO NOT CALL.
     *
     * Destroy.
     * @method CustomView#destroy
     * @intdocs
     */
    public destroy():void {
        this.cleanUp();
        this._eyeContainer = null;
        this._clip = null;
        super.destroy();
    }
}

export default CustomView;
